import React from 'react';
import { useConversation } from './hooks/useConversation';
import InputArea from './components/InputArea';

function App() {
  const { messages, isTyping, currentStep, handleUserAnswer, userData } = useConversation();
  const latestBotMessage = messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text;

  return (
    <div className="container">
      {/* Header Area */}
      <div className="protocol-header">
        NIMHANS CLINICAL PROTOCOL • CONFIDENTIAL
      </div>

      <main className="main-stage">
        <div className="content-scroller">
          {/* Summary View */}
          {!currentStep && !isTyping ? (
            <div className="summary-card">
              <h2>Clinical Intake Summary</h2>
              <div className="summary-list">
                {Object.entries(userData).map(([key, value]) => (
                  <div key={key} className="summary-item">
                    <span className="summary-label">{key.replace(/_/g, ' ')}</span>
                    <span className="summary-value">{Array.isArray(value) ? value.join(", ") : value}</span>
                  </div>
                ))}
              </div>
              <button className="restart-btn" onClick={() => window.location.reload()}>Start New Case</button>
            </div>
          ) : (
            /* Active Question View */
            <div className="question-wrapper">
              {isTyping ? (
                <div className="typing-state">Processing...</div>
              ) : (
                <>
                  <h1 className="hero-question">{latestBotMessage}</h1>
                  <InputArea 
                    currentStep={currentStep} 
                    onSendMessage={handleUserAnswer} 
                    isTyping={isTyping} 
                  />
                </>
              )}
            </div>
          )}
        </div>
      </main>

      {/* Progress Bar */}
      <div 
        className="progress-bar" 
        style={{ width: `${currentStep ? (messages.filter(m => m.sender === 'bot').length / 12) * 100 : 100}%` }} 
      />
    </div>
  );
}

export default App;
